import json
import modal
import numpy as np
from fastapi import FastAPI

app = modal.App("hyperparameter-sweep")

# Define Volume and Dict
volume = modal.Volume.from_name("hp-sweep-experiments", create_if_missing=True)
results_dict = modal.Dict.from_name("hp-sweep-results", create_if_missing=True)

# Define image with numpy
image = modal.Image.debian_slim().pip_install("numpy", "fastapi")

# FastAPI app
web_app = FastAPI()

@web_app.get("/")
def get_best_config():
    # Retrieve from dict
    best_config = results_dict.get("best_config", {})
    experiment_count = results_dict.get("experiment_count", 0)
    return {"best_config": best_config, "experiment_count": experiment_count}

@app.function()
@modal.asgi_app()
def web_endpoint():
    return web_app

@app.cls(image=image, volumes={"/data": volume})
class SweepRunner:
    @modal.enter()
    def setup(self):
        # Setup things if necessary
        pass

    @modal.method()
    def run_experiment(self, lr: float, bs: int):
        # Simulate an experiment
        accuracy = 100.0 - abs(lr - 0.05) * 1000 - abs(bs - 32)

        result = {
            "learning_rate": lr,
            "batch_size": bs,
            "accuracy": accuracy
        }

        # Save to volume
        filename = f"/data/exp_lr_{lr}_bs_{bs}.json"
        with open(filename, "w") as f:
            json.dump(result, f)

        volume.commit()
        return result

@app.local_entrypoint()
def main():
    lrs = np.array([0.01, 0.05, 0.1])
    bss = np.array([16, 32, 64])

    # Create combinations
    combinations = []
    for lr in lrs:
        for bs in bss:
            combinations.append((float(lr), int(bs)))

    runner = SweepRunner()

    best_config = None
    best_accuracy = -float('inf')

    results = list(runner.run_experiment.starmap(combinations))

    for res in results:
        if res["accuracy"] > best_accuracy:
            best_accuracy = res["accuracy"]
            best_config = res

    # Update dict
    results_dict["best_config"] = best_config
    results_dict["experiment_count"] = len(results)

    print(f"Sweep complete. Ran {len(results)} experiments.")
    print(f"Best config: {best_config}")

